import sys, traceback, logging
from functools import wraps

RULE_LIB = {"FileNotFoundError": "create_file", "PermissionError": "fix_permission"}

def intercept_errors(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception as e:
            logging.error(f"Caught exception: {e}")
            cause = analyze_root_cause(e)
            if can_auto_repair(cause):
                auto_repair(cause)
                logging.info("Auto‑repair succeeded")
            else:
                report = generate_introspection_report(e, cause)
                notify_human(report)
            raise
    return wrapper

def analyze_root_cause(exc):
    for rule, action in RULE_LIB.items():
        if rule in str(exc):
            return action
    return "unknown"

def auto_repair(action):
    # 示例自动修复实现
    if action == "create_file":
        pass
    elif action == "fix_permission":
        pass

def generate_introspection_report(exc, cause):
    return {"exception": str(exc), "cause": cause, "trace": traceback.format_exc()}

def notify_human(report):
    print("Human notified:", report)

class ReconnectingWebSocket {
  constructor(url, opts = {}) {
    this.url = url;
    this.attempt = 0;
    this.maxDelay = opts.maxDelay || 30000;
    this.baseDelay = opts.baseDelay || 1000;
    this.connect();
  }
  getDelay() {
    const exp = Math.min(this.baseDelay * 2 ** this.attempt, this.maxDelay);
    return exp / 2 + Math.random() * exp / 2; // full jitter
  }
  connect() {
    this.ws = new WebSocket(this.url);
    this.ws.onclose = () => {
      const delay = this.getDelay();
      this.attempt++;
      setTimeout(() => this.connect(), delay);
    };
    this.ws.onopen = () => { this.attempt = 0; };
  }
}

